    private void BuildYearMonthSelectors()
    {
        AvailableYears = AllSalesData
            .Where(r => r.Year.HasValue)
            .Select(r => r.Year!.Value)
            .Distinct()
            .OrderByDescending(y => y)
            .ToList();

        if (AvailableYears.Count == 0)
        {
            AvailableYears.Add(DateTime.Now.Year);
        }

        if (!AvailableYears.Contains(SelectedYear))
        {
            SelectedYear = AvailableYears.First();
        }

        AvailableMonths = AllSalesData
            .Where(r => !string.IsNullOrEmpty(r.Month))
            .Select(r => r.Month!)
            .Distinct()
            .OrderBy(m =>
            {
                try
                {
                    return DateTime.ParseExact(m, "MMMM", System.Globalization.CultureInfo.InvariantCulture).Month;
                }
                catch
                {
                    return 13;
                }
            })
            .ToList();

        if (AvailableMonths.Count == 0)
        {
            AvailableMonths = new List<string>
            {
                "January", "February", "March", "April", "May", "June",
                "July", "August", "September", "October", "November", "December"
            };
        }

        if (string.IsNullOrEmpty(SelectedMonth) || !AvailableMonths.Contains(SelectedMonth))
        {
            SelectedMonth = DateTime.Now.ToString("MMMM");
        }
    }

