    private string GetFormattedValue(SalesReportItem row, string propertyName)
    {
        var prop = typeof(SalesReportItem).GetProperty(propertyName);
        if (prop == null)
        {
            return string.Empty;
        }

        var value = prop.GetValue(row);
        if (value == null)
        {
            return "-";
        }

        if (propertyName == nameof(SalesReportItem.CCName) && value is string ccVal)
        {
            return ccVal.Replace("&lt;", "").Replace("&gt;", "").Replace("<", string.Empty).Replace(">", string.Empty);
        }
        if (propertyName == nameof(SalesReportItem.Party) && value is string partyVal)
        {
            return partyVal.Replace("&lt;", "").Replace("&gt;", "").Replace("<", string.Empty).Replace(">", string.Empty);
        }
        if (value is decimal decimalValue)
        {
            return decimalValue.ToString("N2");
        }
        if (value is DateTime dateValue)
        {
            return dateValue.ToString("dd MMM yyyy");
        }
        return value.ToString() ?? string.Empty;
    }

