    private void OnFilterOptionChanged(ChangeEventArgs e, FilterOption option)
    {
        if (e.Value is bool isChecked)
        {
            option.Selected = isChecked;
        }
        else
        {
            option.Selected = !option.Selected;
        }
        ApplyFilters();
