    private void ApplyFilters()
    {
        var selectedCostCenters = CostCenters.Where(c => c.Selected && !string.IsNullOrEmpty(c.Name)).Select(c => c.Name!).ToHashSet();
        var selectedMops = ModeOfPayments.Where(m => m.Selected && !string.IsNullOrEmpty(m.Name)).Select(m => m.Name!).ToHashSet();
        var selectedTaxModes = TaxModes.Where(t => t.Selected && !string.IsNullOrEmpty(t.Name)).Select(t => t.Name!).ToHashSet();
        var selectedSalesMen = SalesMan.Where(s => s.Selected && !string.IsNullOrEmpty(s.Name)).Select(s => s.Name!).ToHashSet();
        var selectedVoucherTypes = VoucherTypes.Where(v => v.Selected && !string.IsNullOrEmpty(v.Name)).Select(v => v.Name!).ToHashSet();

        var filtered = AllSalesData.Where(row =>
            (selectedCostCenters.Count == 0 || (!string.IsNullOrEmpty(row.CCName) && selectedCostCenters.Contains(row.CCName))) &&
            (selectedMops.Count == 0 || (!string.IsNullOrEmpty(row.Mop) && selectedMops.Contains(row.Mop))) &&
            (selectedTaxModes.Count == 0 || (!string.IsNullOrEmpty(row.TaxMode) && selectedTaxModes.Contains(row.TaxMode))) &&
            (selectedSalesMen.Count == 0 || (!string.IsNullOrEmpty(row.Salesman) && selectedSalesMen.Contains(row.Salesman))) &&
            (selectedVoucherTypes.Count == 0 || (!string.IsNullOrEmpty(row.VchType) && selectedVoucherTypes.Contains(row.VchType)))
        ).ToList();

        FilteredSalesData = filtered;
        CurrentPage = 1;
        StateHasChanged();
    }

    private async Task ApplyCustomFilter()
    {
        if (ActiveTab == "Custom" && StartDate.HasValue && EndDate.HasValue)
        {
            try
            {
                IsLoading = true;
                ErrorMessage = null;
                FilteredSalesData = new List<SalesReportItem>();

                var url = $"{IBIZWebApp.ApiConstants.BaseUrl}/Mobile/DataRequest";
                var requestBody = new
                {
                    appid = AppID,
                    userId = UserSession.UserId,
                    mobileNo = UserSession.MobileNo,
                    vchType = "SALES",
                    filterCondition = new
                    {
                        fromDate = StartDate.Value.ToString("yyyy-MM-dd"),
                        toDate = EndDate.Value.ToString("yyyy-MM-dd"),
                        vchType = "SALES",
                        paymentMode = (string?)null
                    }
                };

                var request = new HttpRequestMessage(HttpMethod.Post, url)
                {
                    Content = new StringContent(System.Text.Json.JsonSerializer.Serialize(requestBody), System.Text.Encoding.UTF8, "application/json")
                };

                var company = CompanyService.SelectedCompany;
                if (company != null)
                {
                    if (!string.IsNullOrEmpty(company.LicenceKey))
                    {
                        request.Headers.Add("cdkey", company.LicenceKey);
                    }
                    if (!string.IsNullOrEmpty(company.CompanyCode))
                    {
                        request.Headers.Add("companycode", company.CompanyCode);
                    }
                }

                var response = await Http.SendAsync(request);
                if (!response.IsSuccessStatusCode)
                {
                    throw new Exception($"Failed to load custom data: {response.StatusCode}");
                }

                var jsonData = await response.Content.ReadAsStringAsync();
                var options = new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true };
                string? arrayString = null;

                try
                {
                    var wrapper = System.Text.Json.JsonSerializer.Deserialize<DataStringWrapper>(jsonData, options);
                    arrayString = wrapper?.data;
                }
                catch
                {
                    arrayString = null;
                }

                if (string.IsNullOrEmpty(arrayString))
                {
                    arrayString = jsonData;
                }

                List<SalesReportItem>? items = null;
                try
                {
                    if (!string.IsNullOrEmpty(arrayString))
                    {
                        items = System.Text.Json.JsonSerializer.Deserialize<List<SalesReportItem>>(arrayString, options);
                    }
                }
                catch
                {
                }

                FilteredSalesData = items ?? new List<SalesReportItem>();
                if (FilteredSalesData.Count == 0)
                {
                    ErrorMessage = "No sales data available for the selected filters.";
                }
                CurrentPage = 1;
            }
            catch (Exception ex)
            {
                ErrorMessage = $"Error loading custom data: {ex.Message}";
                FilteredSalesData = new List<SalesReportItem>();
            }
            finally
            {
                IsLoading = false;
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    private void PopulateFilters(List<SalesReportItem> items)
    {
        CostCenters = items
            .Where(x => !string.IsNullOrEmpty(x.CCName))
            .Select(x => x.CCName!)
            .Distinct()
            .Select(x => new FilterOption { Name = x, Selected = true })
            .ToList();

        ModeOfPayments = items
            .Where(x => !string.IsNullOrEmpty(x.Mop))
            .Select(x => x.Mop!)
            .Distinct()
            .Select(x => new FilterOption { Name = x, Selected = true })
            .ToList();

        TaxModes = items
            .Where(x => !string.IsNullOrEmpty(x.TaxMode))
            .Select(x => x.TaxMode!)
            .Distinct()
            .Select(x => new FilterOption { Name = x, Selected = true })
            .ToList();

        SalesMan = items
            .Where(x => !string.IsNullOrEmpty(x.Salesman))
            .Select(x => x.Salesman!)
            .Distinct()
            .Select(x => new FilterOption { Name = x, Selected = true })
            .ToList();

        VoucherTypes = items
            .Where(x => !string.IsNullOrEmpty(x.VchType))
            .Select(x => x.VchType!)
            .Distinct()
            .Select(x => new FilterOption { Name = x, Selected = true })
            .ToList();
    }

    private List<SalesReportItem> GetTabData()
    {
        var dataset = FilteredSalesData.Count > 0 ? FilteredSalesData : AllSalesData;
        var now = DateTime.Now;

        switch (ActiveTab)
        {
            case "Today":
                // Always show data with current date (today)
                return AllSalesData.Where(r => !string.IsNullOrEmpty(r.Date) && DateTime.TryParse(r.Date, out var date) && date.Date == now.Date).ToList();
            case "Month":
                return dataset.Where(r =>
                    !string.IsNullOrEmpty(r.Date) &&
                    DateTime.TryParse(r.Date, out var date) &&
                    date.ToString("MMMM") == SelectedMonth &&
                    date.Year == SelectedYear).ToList();
            case "Year":
                return dataset.Where(r =>
                    !string.IsNullOrEmpty(r.Date) &&
                    DateTime.TryParse(r.Date, out var date) &&
                    date.Year == SelectedYear).ToList();
            case "Custom":
                if (StartDate.HasValue && EndDate.HasValue)
                {
                    return dataset.Where(r =>
                        !string.IsNullOrEmpty(r.Date) &&
                        DateTime.TryParse(r.Date, out var date) &&
                        date.Date >= StartDate.Value.Date &&
                        date.Date <= EndDate.Value.Date).ToList();
                }
                return new List<SalesReportItem>();
            case "Summary":
            default:
                var summary = dataset
                    .Where(r => !string.IsNullOrEmpty(r.CCName) && !string.IsNullOrEmpty(r.Month) && r.BillAmt.HasValue)
                    .GroupBy(r => new { r.CCName, r.Month })
                    .Select(g => new SalesReportItem
                    {
                        CCName = g.Key.CCName,
                        Month = g.Key.Month,
                        BillAmt = g.Sum(x => x.BillAmt ?? 0)
                    })
                    .OrderBy(x => x.CCName).ThenBy(x => x.Month)
                    .ToList();
                return summary;
        }
    }

